            { id: 'voice', text: '<b>Community voice:</b> environmental review gives affected residents — often poorer neighborhoods — a way to be heard before harm is done.' },
            { id: 'fund-agencies', text: '<b>Fund and staff, don’t gut:</b> much delay comes from under-resourced agencies; the fix is faster staffing, not weaker standards.' },
            { id: 'litigation-check', text: '<b>Litigation is accountability:</b> the right to sue is a check on bad or illegal projects, not just a delay tactic.' },
            { id: 'irreversible', text: '<b>Some harms are permanent:</b> speeding approvals risks irreversible damage that outlasts any short-term convenience.' }
