          points: [
            { id: 'protect-unborn', text: '<b>Protecting unborn life:</b> opponents hold that a developing fetus is a human life deserving legal protection, which they see as the central moral question.' },
            { id: 'states-decide', text: '<b>Let voters and states decide:</b> opponents argue Dobbs rightly returned a contested moral issue to democratic decision-making in each state rather than the courts.' },
            { id: 'later-term-limits', text: '<b>Limits later in pregnancy:</b> many support restrictions especially later in pregnancy and measures such as born-alive protections, framing these as mainstream limits.' },
            { id: 'medical-oversight', text: '<b>Medical oversight of the pill:</b> opponents argue mifepristone should be dispensed with in-person medical supervision — the core of the FDA / REMS dispute — citing safety and informed consent.' },
            { id: 'federalism-enforcement', text: '<b>States should be able to enforce their laws:</b> opponents argue ban states should not be undercut by pills mailed in from “shield” states, and that federal rules should not override state choices.' }
          ]
