          { date: 'Feb. 28, 2025', text: 'A televised Oval Office clash between Presidents Trump and Zelensky (with Vice President Vance) marks a sharp turn toward pressing Ukraine to negotiate rather than fight on.', src: { label: 'The Washington Post — “beginning of the end”', url: 'https://www.washingtonpost.com/politics/2026/05/08/president-donald-trump/23ea37b8-4ad8-11f1-a119-857cd2bf4fd4_story.html' } },
          { date: '2025–2026', text: 'The administration pursues a negotiated settlement. A U.S. framework would trade territory, bar NATO membership, and cap Ukraine’s military, while European allies float 24- and 28-point counterproposals that soften the limits.', src: { label: 'CSIS — the unfinished plan for peace, provision by provision', url: 'https://www.csis.org/analysis/unfinished-plan-peace-ukraine-provision-provision' } },
          { date: 'May 9–11, 2026', text: 'Trump brokers a three-day ceasefire and a 1,000-for-1,000 prisoner exchange timed to Russia’s Victory Day; Secretary Rubio says broader mediation has “stagnated,” and Russia stresses the truce is only three days.', src: { label: 'NPR — Trump announces a 3-day ceasefire', url: 'https://www.npr.org/2026/05/09/nx-s1-5816478/trump-russia-ukraine-ceasefire' } },
          { date: 'Mid-2026', text: 'Talks continue in fits and starts — Ukraine’s negotiator meets U.S. officials in Miami — but a durable ceasefire remains elusive as Russia presses a war of attrition.', src: { label: 'Al Jazeera — three-day ceasefire and stalled talks', url: 'https://www.aljazeera.com/news/2026/5/8/trump-announces-three-day-ceasefire-in-russia-ukraine-war' } }
