          { date: '1983', text: 'The last major bipartisan Social Security overhaul (following the Greenspan Commission) gradually raises the retirement age and payroll taxes to shore up the system.', src: { label: 'Bipartisan Policy Center — Trustees report explained', url: 'https://bipartisanpolicy.org/explainer/2026-social-security-trustees-report-explained/' } },
          { date: '2010s–2024', text: 'Trustees repeatedly warn of approaching insolvency as the baby boomers retire and the ratio of workers to beneficiaries falls.', src: { label: 'CRFB — Trustees approaching insolvency', url: 'https://www.crfb.org/press-releases/trustees-warn-social-security-and-medicare-are-approaching-insolvency' } },
          { date: 'Jul. 2025', text: 'The One Big Beautiful Bill Act’s senior tax provisions reduce trust-fund revenue — later cited as a reason the insolvency dates moved up.', src: { label: 'CRFB — 2026 Trustees reports', url: 'https://www.crfb.org/blogs/social-security-and-medicare-trustees-release-2026-reports' } },
          { date: 'Jun. 9, 2026', text: 'The Trustees project Social Security’s retirement fund pays full benefits only through about 2032 and Medicare’s Part A fund through about 2033 — the worst outlook in decades.', src: { label: 'AARP — 2026 trust-fund report', url: 'https://www.aarp.org/social-security/trust-fund-report-2026/' } }
