          { date: '2025–2026', text: 'BSCA grants, red-flag programs, and 988 crisis services continue scaling up; broader federal proposals (universal background checks, an assault-weapons ban, national red-flag standards) remain stalled, and the fight shifts to the states and the courts.', src: { label: 'Everytown — state gun-law tracker', url: 'https://everytownresearch.org/rankings/' } }
