          { date: '2025–2026', text: 'The 2025 reconciliation law phases down many renewable tax credits while supporting nuclear; states debate their clean-energy standards, and SMR licensing and fuel-supply build-out continue.', src: { label: 'CRS — federal energy tax credits and the 2025 law', url: 'https://crsreports.congress.gov/' } }
