            { id: 'due-process', text: '<b>Due process:</b> naming people who have not been charged can destroy reputations without evidence or a chance to respond.' },
            { id: 'ongoing-investigations', text: '<b>Ongoing investigations:</b> prosecutors argue some material must stay sealed to protect active or potential cases.' },
            { id: 'raw-file-accuracy', text: '<b>Raw-file accuracy:</b> investigative files include unverified tips and names pulled for lineups, which can mislead if released without context.' },
            { id: 'legal-limits', text: '<b>Legal limits:</b> grand-jury secrecy and court rules restrict what can lawfully be disclosed, regardless of public demand.' }
