              { id: 'zack_stratton', name: 'Zack Stratton', office: 'Vineyard · Mayor', icon: '🏛', topic: 'Redevelopment Agency Reform', strength: 'limited', pledge: true, impact: 'RDA reform named top priority · record still to be written' }
